def factorial(n):
    if n <= 1:      # condición de terminación
        return 1
    return n * factorial(n - 1)

print(factorial(4))

class Sensor:
    def __init__(self, nombre, unidad):
        self.nombre = nombre
        self.unidad = unidad
    def describir(self):
        return f"{self.nombre} (mide en {self.unidad})"

s = Sensor("DHT22", "°C")
print(s.describir())

